var e=JSON.parse(`[{"id":"L2_1","type":"dialog","speaker":"ESTAROSSA_NPC_NULL_NULL","text":{"KOREA":"시간이 얼마나 지났지?","JPN":"どれくらいの時間が過ぎたのだろう？","ENG":"How long was I out?","TWN":"時間過多久了？"},"stage":{"bg":"BLACK","slots":{"L":null,"C":null,"R":null}}},{"id":"L3_1","type":"dialog","speaker":"ESTAROSSA_NPC_NULL_NULL","text":{"KOREA":"조금… 소란스러운 것 같은데.","JPN":"少し……騒がしいようだが。","ENG":"Things sound... a bit noisy.","TWN":"好像……有點吵。"},"stage":{"bg":"BLACK","slots":{"L":null,"C":null,"R":null}}},{"id":"L5_1","type":"dialog","speaker":"ESTAROSSA_NPC_NULL_NULL","text":{"KOREA":"이번에도 낯선 천장인가.","JPN":"今回も見知らぬ天井か。","ENG":"Another unfamiliar ceiling.","TWN":"這次也是陌生的天花板嗎？"},"stage":{"bg":"BLACK","slots":{"L":null,"C":{"char_id":"ESTAROSSA_NPC_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":"ESTAROSSA_NPC_NULL_NULL","text":{"KOREA":"흔들려서… 누워있기 불편하군.","JPN":"揺れていて……寝心地が悪い。","ENG":"It's shaking... so not the most comfortable spot to lie down.","TWN":"搖搖晃晃的……躺著也不舒服。"},"stage":{"bg":"BLACK","slots":{"L":null,"C":{"char_id":"ESTAROSSA_NPC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":"ESTAROSSA_NPC_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"BLACK","slots":{"L":null,"C":{"char_id":"ESTAROSSA_NPC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L8_1","type":"dialog","speaker":"ESTAROSSA_NPC_NULL_NULL","text":{"KOREA":"잠깐, 흔들린다고?","JPN":"揺れているだと？","ENG":"Wait. Shaking?","TWN":"等等，搖晃嗎？"},"stage":{"bg":"BLACK","slots":{"L":null,"C":{"char_id":"ESTAROSSA_NPC_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L10_1","type":"dialog","speaker":"ESTAROSSA_NPC_NULL_NULL","text":{"KOREA":"하아… 하아…….","JPN":"はあ……はあ……","ENG":"*Huff...* *Huff...*","TWN":"哈……哈……"},"stage":{"bg":"COUNTERSIDE_FOREST","slots":{"L":null,"C":{"char_id":"ESTAROSSA_NPC_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L11_1","type":"dialog","speaker":"ESTAROSSA_NPC_NULL_NULL","text":{"KOREA":"어떻게 된 거지? 나는 분명, 침식체와 싸우고 있었는데?","JPN":"どういうことだ？　私は確か、侵食体と戦っていたはず。","ENG":"What happened? I was fighting a C.O...","TWN":"這是怎麼回事？我明明在和侵蝕體戰鬥？"},"stage":{"bg":"COUNTERSIDE_FOREST","slots":{"L":null,"C":{"char_id":"ESTAROSSA_NPC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"COACHMAN_ROOT_NPC_NULL","text":{"KOREA":"아니, 갑자기 위험하게 튀어나오시면 어떡합니까?","JPN":"ちょっと、いきなり外に飛び出るなんて危ないじゃないですか！","ENG":"Hey! You can't just pop out like that! That's dangerous!","TWN":"不，不可以這樣突然地衝出去啊！"},"stage":{"bg":"COUNTERSIDE_FOREST","slots":{"L":null,"C":{"char_id":"ESTAROSSA_NPC_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"COACHMAN_ROOT_NPC_NULL","text":{"KOREA":"천천히 가고 있었으니 망정이지. 속도라도 냈으면 큰일이라고요!","JPN":"ゆっくり行ってたから良かったものの。速度が出てたら大変なことになってましたよ！","ENG":"Good thing we were going slow! If we'd been going faster, it would've been a disaster!","TWN":"幸好走得慢。如果加速的話，那可就麻煩了！"},"stage":{"bg":"COUNTERSIDE_FOREST","slots":{"L":null,"C":{"char_id":"ESTAROSSA_NPC_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"ESTAROSSA_NPC_NULL_NULL","text":{"KOREA":"걱정 마라. 별의 가호를 다루지 못한다 한들 그 정도는 아무렇지도 않아.","JPN":"心配するな。星の加護を扱えないとはいえ、それくらいは問題ない。","ENG":"No need to worry. Even without the Blessing of the Stars, that much wouldn't have harmed me.","TWN":"別擔心。即使無法掌控星星的守護，那也沒什麼大不了的。"},"stage":{"bg":"COUNTERSIDE_FOREST","slots":{"L":null,"C":{"char_id":"ESTAROSSA_NPC_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"ESTAROSSA_NPC_NULL_NULL","text":{"KOREA":"무엇보다 납치범이 걱정할 부분은 아니다.","JPN":"何より誘拐犯が心配するようなことではなかろう。","ENG":"Besides, it's not something a kidnapper should be fretting over.","TWN":"也用不著你這個綁架犯擔心。"},"stage":{"bg":"COUNTERSIDE_FOREST","slots":{"L":null,"C":{"char_id":"ESTAROSSA_NPC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"COACHMAN_ROOT_NPC_NULL","text":{"KOREA":"무슨 말씀이십니까? 제가 무슨 능력이 있다고 기사님을 납치해요?","JPN":"どういう意味ですか？　なぜ私が騎士様を誘拐するんですか？","ENG":"Kidnapper?! What are you talking about? I don't have the means to kidnap a knight!","TWN":"你在說什麼呢？我哪有什麼能力可以綁架你？"},"stage":{"bg":"COUNTERSIDE_FOREST","slots":{"L":null,"C":{"char_id":"ESTAROSSA_NPC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"COACHMAN_ROOT_NPC_NULL","text":{"KOREA":"그리고 기사님이 아니라 제 안위를 걱정한 겁니다!","JPN":"それに、騎士様じゃなくて自分の心配をしたんです！","ENG":"And I wasn't worried about you! I was worried about myself!","TWN":"而且我不是擔心你，我是擔心我的安危！"},"stage":{"bg":"COUNTERSIDE_FOREST","slots":{"L":null,"C":{"char_id":"ESTAROSSA_NPC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L21_1","type":"dialog","speaker":"COACHMAN_ROOT_NPC_NULL","text":{"KOREA":"말이 놀라 흥분하기라도 하면 마차가 뒤집힐 텐데, 그럼 일반인인 저는 어떡하라고요?","JPN":"馬が驚いて興奮すると馬車が倒れるだろうし、そうなったら一般人の私にどうしろと？","ENG":"If my horse got spooked and the carriage flipped, what do you think would've happened to a civilian like me?","TWN":"如果馬受到驚嚇而激動起來，馬車就會翻倒，那我這個普通人該怎麼辦呢？"},"stage":{"bg":"COUNTERSIDE_FOREST","slots":{"L":null,"C":{"char_id":"ESTAROSSA_NPC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"COACHMAN_ROOT_NPC_NULL","text":{"KOREA":"백작가의 기사들이 튼튼하다고 자랑이라도 하는 겁니까?","JPN":"伯爵家の騎士は丈夫だって自慢でもするつもりなんですか？","ENG":"Is this supposed to be some humblebrag about how sturdy the knights of the Count's house are?","TWN":"伯爵家的騎士們是不是都喜歡炫耀他們的強壯呢？"},"stage":{"bg":"COUNTERSIDE_FOREST","slots":{"L":null,"C":{"char_id":"ESTAROSSA_NPC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L23_1","type":"dialog","speaker":"ESTAROSSA_NPC_NULL_NULL","text":{"KOREA":"……백작가라고?","JPN":"……伯爵家だと？","ENG":"...Count's house?","TWN":"……伯爵家嗎？"},"stage":{"bg":"COUNTERSIDE_FOREST","slots":{"L":null,"C":{"char_id":"ESTAROSSA_NPC_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L25_1","type":"dialog","speaker":"PRESIDENT_SCHOOL_QM_NULL","text":{"KOREA":"죄송합니다, 클링턴 씨. 잠꾸러기인 제 호위가 꿈을 현실과 혼동한 모양이네요.","JPN":"申し訳ありません、クリントンさん。私の護衛がつい寝ぼけて、夢と現を混同しているようです。","ENG":"Apologies, Mr. Clinton. My sleepyhead escort seems to have mistaken dreams for reality again.","TWN":"抱歉，克林頓先生。看來我那愛睡覺的護衛把夢境和現實搞混了。"},"stage":{"bg":"COUNTERSIDE_FOREST","slots":{"L":null,"C":null,"R":null}}},{"id":"L26_1","type":"dialog","speaker":"COACHMAN_ROOT_NPC_NULL","text":{"KOREA":"아무리 그래도 그렇죠! 목숨 걸고 일하는 사람을 납치범 취급하는 게 가당키나 합니까요?","JPN":"だとしても、あんまりです！　命懸けで働いてる人を誘拐犯扱いするなんて！","ENG":"Even so! Calling someone risking their life a kidnapper?! That's not right!","TWN":"再怎麼說也不能這樣吧！把拼命工作的人當成綁匪，這合理嗎？"},"stage":{"bg":"COUNTERSIDE_FOREST","slots":{"L":null,"C":null,"R":null}}},{"id":"L27_1","type":"dialog","speaker":"COACHMAN_ROOT_NPC_NULL","text":{"KOREA":"<color=#ffd34c>그레이스</color>님의 부탁이라도 못 참아요! 이렇게는 일 못합니다!","JPN":"いくら<color=#ffd34c>グレース</color>様の頼みでも我慢なりません！　これでは仕事などできませんね！","ENG":"Even if it's <color=#ffd34c>Lady Grace</color> asking, this is too much! I can't work like this!","TWN":"即使是<color=#ffd34c>葛瑞絲</color>小姐開口我也無法忍受！這樣我沒法工作！"},"stage":{"bg":"COUNTERSIDE_FOREST","slots":{"L":null,"C":null,"R":null}}},{"id":"L28_1","type":"dialog","speaker":"GRACE_ORDER_NULL_NULL","text":{"KOREA":"예. 찬도에 출발한 시각이 벌써 조과에 달하였으니, 그대의 노고는 이해하는 바입니다.","JPN":"そうですよね。夕方に出発してもう朝ですので、貴方のご苦労は理解いたします。","ENG":"Yes. Since we've been on the road since dawn, I understand your frustration.","TWN":"是的。從出發到目的地的時間已經接近中午，我理解你的辛苦。"},"stage":{"bg":"COUNTERSIDE_FOREST","slots":{"L":null,"C":{"char_id":"GRACE_ORDER_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L29_1","type":"dialog","speaker":"GRACE_ORDER_NULL_NULL","text":{"KOREA":"제도에 도착하면 불렀던 값의 배를 지출할 터니, 부디 노여움을 거둬 주시죠.","JPN":"帝都に到着しましたら費用を2倍お支払いしますので、どうかお許しください。","ENG":"I'll pay you double once we reach the capital, so please calm yourself.","TWN":"到首都都後，我會支付雙倍的費用，請你息怒。"},"stage":{"bg":"COUNTERSIDE_FOREST","slots":{"L":null,"C":{"char_id":"GRACE_ORDER_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L31_1","type":"dialog","speaker":"COACHMAN_ROOT_NPC_NULL","text":{"KOREA":"혈기왕성한 나이에 마차 문 좀 찰 수 있죠! 제국의 수도까지 쾌적하게 모시겠습니다!","JPN":"育ち盛りですし馬車の扉を蹴とばすことぐらいありますよね！　帝国の首都まで安全にご案内いたしましょう！","ENG":"I might be young, but I know how to slam a carriage door! I'll get you to the imperial capital in comfort!","TWN":"在年輕氣盛的年紀，踢車門再正常不過了哈哈！我會護送你舒舒服服的到達首都的！"},"stage":{"bg":"COUNTERSIDE_FOREST","slots":{"L":null,"C":{"char_id":"GRACE_ORDER_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L33_1","type":"dialog","speaker":"GRACE_ORDER_NULL_NULL","text":{"KOREA":"기운차라. 혹시 수컷인가요?","JPN":"元気ですね。もしかして雄馬ですか？","ENG":"So spirited. Is your horse male?","TWN":"振作起來。這馬是公的嗎？"},"stage":{"bg":"COUNTERSIDE_FOREST","slots":{"L":null,"C":{"char_id":"GRACE_ORDER_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L35_1","type":"dialog","speaker":"COACHMAN_ROOT_NPC_NULL","text":{"KOREA":"암말입니다!","JPN":"雌馬です！","ENG":"It's a mare!","TWN":"才不是！"},"stage":{"bg":"COUNTERSIDE_FOREST","slots":{"L":null,"C":{"char_id":"GRACE_ORDER_NULL_NULL","face":"UNIT_IDLE"},"R":null}}}]`);export{e as default};